local assets = {Asset( "ANIM" , "anim/dyc_reticuleaoe.zip" ),} local function SetAlertRing(inst, duration, revealTime) inst:SetColor(0x1, 0x0, 0x0, 0x1) local delay = 0.333 duration = duration or 0x2 duration = math.max(duration, 0.1) revealTime = revealTime or duration revealTime = math.min(duration, revealTime) local changeTime = math.max(0.01, math.min(0.5, duration - revealTime)) inst.AnimState:SetMultColour(0x1, 0x0, 0x0, 0x0) local timer = duration + delay inst:DoPeriodicTask(FRAMES, function() inst.Transform:SetRotation(inst:GetRotation() + 0x1) timer = timer - FRAMES if timer <= 0x0 then inst:Remove() return end local c = inst.color if timer <= delay then inst.AnimState:SetMultColour(c.r, c.g, c.b, c.a * timer / delay) elseif timer <= delay + revealTime then inst.AnimState:SetMultColour(c.r, c.g, c.b, c.a) elseif timer <= delay + revealTime + changeTime then inst.AnimState:SetMultColour(c.r, c.g, c.b, c.a * ( - timer + delay + revealTime + changeTime) / changeTime) end end) return inst end local function SetRadius(inst, r) r = r or 0x1 if r >= 5.5 then inst.AnimState:PlayAnimation( "idle_target" ) inst.AnimState:SetScale(r * 0.375, r * 0.375) elseif r >= 1.5 then inst.AnimState:PlayAnimation( "idle" ) inst.AnimState:SetScale(r * 0.375, r * 0.375) else inst.AnimState:PlayAnimation( "idle_small" ) inst.AnimState:SetScale(r * 0.75, r * 0.75) end return inst end local function SetColor(inst, r, g, b, a) inst.color.r = r or 0x1 inst.color.g = g or 0x1 inst.color.b = b or 0x1 inst.color.a = a or 0x1 return inst end local function fn() local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() inst.Transform:SetFourFaced() anim:SetBank( "reticuleaoe" ) anim:SetBuild( "dyc_reticuleaoe" ) anim:PlayAnimation( "idle" ) anim:SetLightOverride(0x1) anim:SetBloomEffectHandle( "shaders/anim.ksh" ) anim:SetOrientation(ANIM_ORIENTATION.OnGround) anim:SetLayer(LAYER_WORLD_BACKGROUND) anim:SetSortOrder(0x3) inst:AddTag( "fx" ) inst:AddTag( "NOCLICK" ) inst.persists = false inst.color = {r = 0x1, g = 0x1, b = 0x1, a = 0x1} inst.SetRadius = SetRadius inst.SetAlertRing = SetAlertRing inst.SetColor = SetColor return inst end return Prefab( "common/fx/dyc_fx_aoering" , fn, assets) 